INSERT INTO promotions (title, description, discount_percent, original_price, sale_price, start_date, end_date, is_active) VALUES
('โปรฯ ต้อนรับสมาชิกใหม่', 'สมัครสมาชิกวันนี้ รับส่วนลด 20% สำหรับการสั่งซื้อครั้งแรก ไม่จำกัดจำนวนสินค้า', 20, 1290, 1032, '2026-07-01', '2026-07-31', true),
('แพ็คเกจสุขภาพดี ซื้อ 3 แถม 1', 'ซื้อวิตามินและอาหารเสริม 3 ชิ้น แถมฟรีอีก 1 ชิ้น มูลค่าสูงสุด 590 บาท', 25, 2370, 1770, '2026-07-01', '2026-07-15', true),
('ลดพิเศษ คอลลาเจน & กลูตา', 'ซื้อคอลลาเจนและกลูตาไธโอนคู่กัน ลดทันที 30% จากราคาปกติ', 30, 2080, 1456, '2026-07-05', '2026-07-20', true),
('Flash Sale ทุกวันศุกร์', 'ลดสูงสุด 40% คัดเฉพาะสินค้าขายดี เฉพาะวันศุกร์เท่านั้น ของมีจำนวนจำกัด', 40, 1290, 774, '2026-07-04', '2026-07-31', true);
INSERT INTO hall_of_fame (name, level, description, achievement, month, year) VALUES
('คุณสมหมาย ใจดี', 'Diamond', 'ผู้บริหารระดับสูงสุด ที่มีผลงานยอดเยี่ยมและเป็นแบบอย่างให้แก่ทีมงานทั่วประเทศ', 'ยอดขายสะสมสูงสุดกว่า 50 ล้านบาท สร้างทีมกว่า 1,200 คน', 'มิถุนายน', 2026),
('คุณสมหญิง รักดี', 'Diamond Crown', 'นักขายมืออาชีพ ผู้สร้างทีมแกร่งและมีวิสัยทัศน์กว้างไกลในการพัฒนาธุรกิจ', 'ยอดขายรวม 30 ล้านบาท สร้างทีมกว่า 800 คน', 'มิถุนายน', 2026),
('คุณวิชาญ เก่งกาจ', 'Diamond Blue', 'ผู้นำทีมที่มีความสามารถโดดเด่น สร้างแรงบันดาลใจให้ทีมงานก้าวหน้าอย่างต่อเนื่อง', 'ยอดขายรวม 20 ล้านบาท สร้างทีมกว่า 500 คน', 'มิถุนายน', 2026),
('คุณนภา สดใส', 'President Black', 'ผู้บริหารที่มีวิสัยทัศน์กว้างไกล บริหารทีมงานได้อย่างมีประสิทธิภาพ', 'ยอดขายรวม 12 ล้านบาท สร้างทีมกว่า 300 คน', 'มิถุนายน', 2026),
('คุณธนา มั่งมี', 'Vice President', 'ผู้นำทีมที่มีทักษะการบริหารสูง พัฒนาทีมงานได้อย่างต่อเนื่อง', 'ยอดขายรวม 6 ล้านบาท สร้างทีมกว่า 150 คน', 'มิถุนายน', 2026),
('คุณสุนีย์ ดีเลิศ', 'Manager Director', 'ผู้จัดการที่มีความสามารถรอบด้าน บริหารและพัฒนาทีมได้อย่างดีเยี่ยม', 'ยอดขายรวม 2.5 ล้านบาท สร้างทีมกว่า 80 คน', 'มิถุนายน', 2026),
('คุณประทีป ยิ้มแย้ม', 'Super Star', 'นักขายดาวเด่น ที่มีผลงานโดดเด่นและเป็นที่รักของลูกค้า', 'ยอดขายรวม 1.2 ล้านบาท สร้างทีมกว่า 40 คน', 'มิถุนายน', 2026),
('คุณรัตนา ใจงาม', 'Sky Star', 'นักขายดาวรุ่ง ที่มีศักยภาพสูงและความมุ่งมั่นในการพัฒนาตัวเอง', 'ยอดขายรวม 600,000 บาท สร้างทีมกว่า 20 คน', 'มิถุนายน', 2026),
('คุณชัยชนะ ก้าวหน้า', 'Diamond', 'นักธุรกิจมืออาชีพ ผู้สร้างเครือข่ายธุรกิจที่แข็งแกร่งทั่วประเทศ', 'ยอดขายสะสม 45 ล้านบาท สร้างทีมกว่า 1,000 คน', 'พฤษภาคม', 2026),
('คุณลดาวัลย์ สุขใจ', 'Diamond Crown', 'ผู้นำสตรีที่เข้มแข็ง สร้างแรงบันดาลใจให้ผู้หญิงทั่วประเทศ', 'ยอดขายรวม 28 ล้านบาท สร้างทีมกว่า 700 คน', 'พฤษภาคม', 2026);
INSERT INTO activities (title, description, activity_date, location) VALUES
('งานสัมมนาใหญ่ประจำปี 2026', 'สัมมนาและฝึกอบรมผู้แทนจำหน่ายทั่วประเทศกว่า 2,000 คน พร้อมพิธีมอบรางวัล Hall of Fame ประจำปี', '2026-06-15', 'ศูนย์การประชุมแห่งชาติสิริกิติ์ กรุงเทพฯ'),
('กิจกรรม CSR ปลูกป่าชายเลน', 'ปลูกต้นไม้กว่า 5,000 ต้น เพื่อฟื้นฟูระบบนิเวศชายฝั่ง ร่วมกับพนักงานและผู้แทนจำหน่ายกว่า 300 คน', '2026-05-20', 'อ่าวไทย จังหวัดสมุทรสาคร'),
('อบรมผู้แทนจำหน่ายใหม่ รุ่น 25', 'อบรมความรู้เชิงลึกเกี่ยวกับผลิตภัณฑ์ ทักษะการขาย และการสร้างทีมงาน สำหรับผู้แทนจำหน่ายใหม่', '2026-07-10', 'สำนักงานใหญ่ บัวหลวง เฮลธ์ กรุงเทพฯ'),
('เทศกาลสุขภาพ Bualuang Health Fair', 'งานมหกรรมสุขภาพ ออกบูธให้คำปรึกษาด้านสุขภาพ สาธิตผลิตภัณฑ์ และกิจกรรมเพื่อสุขภาพมากมาย', '2026-08-05', 'สยามพารากอน กรุงเทพฯ'),
('ทริปท่องเที่ยวรางวัลผู้บริหาร Top 100', 'ทริปพิเศษสำหรับผู้แทนจำหน่ายที่มียอดขายสูงสุด 100 อันดับแรก ประจำครึ่งปีแรก 2026', '2026-09-15', 'เกาะบาหลี ประเทศอินโดนีเซีย');
